class Solution:
    def closestToTarget(self, arr, target):
        n = len(arr)
        best = abs(arr[0] - target)
        if n <= 2000:
            for l in range(n):
                cur = arr[l]
                if abs(cur - target) < best:
                    best = abs(cur - target)
                for r in range(l + 1, n):
                    cur &= arr[r]
                    if abs(cur - target) < best:
                        best = abs(cur - target)
            return best
        prev = set()
        for num in arr:
            cur = {num}
            for p in prev:
                cur.add(p & num)
            for v in cur:
                d = abs(v - target)
                if d < best:
                    best = d
            prev = cur
        return best

