var closestToTarget = function(arr, target) {
    let best = Math.abs(arr[0] - target);
    let prev = new Set();
    for (const num of arr) {
        const cur = new Set([num]);
        for (const p of prev) cur.add(p & num);
        for (const v of cur) {
            const d = Math.abs(v - target);
            if (d < best) best = d;
        }
        prev = cur;
    }
    return best;
};
